class Solution(object):
    def maxSum(self, nums):
        from collections import defaultdict
        groups = defaultdict(list)
        for x in nums:
            groups[max(int(d) for d in str(x))].append(x)
        best = -1
        for g in groups.values():
            if len(g) >= 2:
                g.sort(reverse=True)
                best = max(best, g[0] + g[1])
        return best
